// ✅ الحل الصحيح: atomic مع ترتيب ذاكرة
#include <atomic>
std::atomic<bool> ready{false};
int data = 0;

void producer() {
    data = 42;
    ready.store(true, std::memory_order_release);
    // release يضمن أن data=42 مرئي عند الاستيقاظ
}

void consumer() {
    while (!ready.load(std::memory_order_acquire)) {}
    // acquire يضمن رؤية data=42 المكتوب قبل release
    // data مضمون: 42
}

